module top_alu_module(
    input [3:0] operand1,
    input [3:0] b,
    input [1:0] op,
    output reg [3:0] result);always @(*) begin
        case (op)
            2'b00: result <= operand1 + b;
            2'b01: result <= operand1 - b;
            2'b10: result <= operand1 & b;
            2'b11: result <= operand1 | b;
        endcase
    end

endmodule
